import { jsPDF } from 'jspdf'
import autoTable, { type CellHookData } from 'jspdf-autotable'

// --- Logo (embedded base64 — white variant) ---

const LOGO_BASE64 = 'data:image/png;base64,'


// --- Types ---

export interface AlertItem {
  id: string | number
  sev: 'critical' | 'high' | 'medium' | 'low'
  cat: string
  msg: string
  time: string
}

export interface TrustPoint {
  t: string
  score: number
}

export interface TranscriptLine {
  speaker?: string
  timestamp: string
  text: string
  suspicious?: boolean
}

export interface ReportPayload {
  id: string
  title: string
  date: string
  duration: string
  durationMins: number
  meetingType?: string
  participants: number
  trustAvg: number
  visualScore?: number
  audioScore?: number
  dominantEmotions?: string[]
  modelUsed?: string
  alerts: {
    total: number
    critical: number
    high: number
    medium: number
    low: number
  }
  timeline: AlertItem[]
  trustCurve: TrustPoint[]
  transcript?: TranscriptLine[]
}

// --- Color Palette (print-optimized) ---

const C = {
  // Backgrounds
  pageBg:      [255, 255, 255] as [number, number, number],
  headerBanner:[15,  15,  30]  as [number, number, number],  // #0F0F1E dark navy
  rowAlt:      [248, 250, 252] as [number, number, number],  // barely-gray alt rows

  // Text
  textPrimary: [26,  26,  46]  as [number, number, number],  // #1A1A2E
  textBody:    [55,  65,  81]  as [number, number, number],  // #374151
  textLabel:   [107, 114, 128] as [number, number, number],  // #6B7280
  textFooter:  [156, 163, 175] as [number, number, number],  // #9CA3AF
  textOnDark:  [255, 255, 255] as [number, number, number],
  textSubtitle:[160, 160, 175] as [number, number, number],  // #A0A0AF

  // Brand accent — thin rules only, never on text
  cyan:        [34,  211, 238] as [number, number, number],  // #22D3EE

  // Table header
  tableHead:   [26,  26,  46]  as [number, number, number],  // #1A1A2E fill

  // Borders
  border:      [229, 231, 235] as [number, number, number],  // #E5E7EB
  borderLight: [243, 244, 246] as [number, number, number],

  // Severity — WCAG AA-compliant on white
  sevCritical: [220, 38,  38]  as [number, number, number],  // #DC2626
  sevHigh:     [234, 88,  12]  as [number, number, number],  // #EA580C
  sevMedium:   [202, 138, 4]   as [number, number, number],  // #CA8A04
  sevLow:      [22,  163, 74]  as [number, number, number],  // #16A34A

  // Risk (trust score coloring)
  riskGreen:   [22,  163, 74]  as [number, number, number],
  riskAmber:   [202, 138, 4]   as [number, number, number],
  riskRed:     [220, 38,  38]  as [number, number, number],
} as const

// A4 dimensions (mm)
const PAGE_W  = 210
const PAGE_H  = 297
const MARGIN  = 20
const CONT_W  = PAGE_W - MARGIN * 2  // 170mm
const FOOTER_Y = PAGE_H - 10

// --- Utility helpers ---

function fill(doc: jsPDF, c: readonly [number, number, number]) {
  doc.setFillColor(c[0], c[1], c[2])
}

function draw(doc: jsPDF, c: readonly [number, number, number]) {
  doc.setDrawColor(c[0], c[1], c[2])
}

function txt(doc: jsPDF, c: readonly [number, number, number]) {
  doc.setTextColor(c[0], c[1], c[2])
}

function riskColor(score: number): readonly [number, number, number] {
  if (score >= 80) return C.riskGreen
  if (score >= 60) return C.riskAmber
  return C.riskRed
}

function riskLabel(score: number): string {
  if (score >= 80) return 'LOW RISK'
  if (score >= 60) return 'ELEVATED RISK'
  return 'HIGH RISK'
}

function sevColor(sev: string): readonly [number, number, number] {
  switch (sev.toLowerCase()) {
    case 'critical': return C.sevCritical
    case 'high':     return C.sevHigh
    case 'medium':   return C.sevMedium
    default:         return C.sevLow
  }
}

/** Thin horizontal rule */
function hRule(doc: jsPDF, y: number, color: readonly [number, number, number] = C.border, width = 0.25) {
  draw(doc, color)
  doc.setLineWidth(width)
  doc.line(MARGIN, y, PAGE_W - MARGIN, y)
}

/** Thin cyan accent rule (0.5pt) */
function cyanRule(doc: jsPDF, y: number) {
  draw(doc, C.cyan)
  doc.setLineWidth(0.5)
  doc.line(0, y, PAGE_W, y)
}

/** Draw page footer on every page */
function drawFooter(doc: jsPDF, pageNum: number, totalPages: number) {
  // Gray rule above footer
  draw(doc, C.border)
  doc.setLineWidth(0.25)
  doc.line(MARGIN, FOOTER_Y - 4, PAGE_W - MARGIN, FOOTER_Y - 4)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(7)
  txt(doc, C.textFooter)
  doc.text('RealSync — AI-Powered Meeting Intelligence — Confidential', MARGIN, FOOTER_Y)
  doc.text(`Page ${pageNum} of ${totalPages}`, PAGE_W - MARGIN, FOOTER_Y, { align: 'right' })
}

/** Section heading: 12pt bold #1A1A2E */
function sectionHeading(doc: jsPDF, y: number, title: string): number {
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(12)
  txt(doc, C.textPrimary)
  doc.text(title, MARGIN, y)
  hRule(doc, y + 3, C.border)
  return y + 9
}

/** Progress bar (flat, no rounded corners to avoid jsPDF quirks) */
function progressBar(
  doc: jsPDF,
  x: number, y: number, w: number,
  score: number,
  color: readonly [number, number, number],
) {
  const h = 2.5
  fill(doc, C.border)
  doc.rect(x, y, w, h, 'F')
  const fw = Math.max(2, (score / 100) * w)
  fill(doc, color)
  doc.rect(x, y, fw, h, 'F')
}

// --- Generate summary paragraph ---

function buildSummaryText(report: ReportPayload): string {
  const rLabel = riskLabel(report.trustAvg).toLowerCase()
  const alertPart = report.alerts.total === 0
    ? 'No security alerts were raised during this session; all signals remained within acceptable thresholds.'
    : `${report.alerts.total} alert${report.alerts.total !== 1 ? 's' : ''} were detected (${report.alerts.critical} critical, ${report.alerts.high} high, ${report.alerts.medium} medium, ${report.alerts.low} low).`
  return (
    `Session "${report.title}" was analysed by the RealSync AI pipeline on ${report.date} ` +
    `with a session duration of ${report.duration}. The overall trust score of ${report.trustAvg}% ` +
    `places this meeting in the ${rLabel} category. ` +
    alertPart
  )
}

// --- PAGE 1: Cover + Executive Summary ---

function buildPage1(doc: jsPDF, report: ReportPayload, totalPages: number) {
  // White background
  fill(doc, C.pageBg)
  doc.rect(0, 0, PAGE_W, PAGE_H, 'F')

  // ── Dark navy header banner (32mm) ─────────────────────────────
  const BANNER_H = 32
  fill(doc, C.headerBanner)
  doc.rect(0, 0, PAGE_W, BANNER_H, 'F')

  // Logo — left side of banner
  try {
    doc.addImage(LOGO_BASE64, 'PNG', MARGIN, 1, 30, 30, undefined, 'NONE')
  } catch {
    // Logo unavailable — skip silently
  }

  // "RealSync" wordmark beside logo
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(16)
  txt(doc, C.textOnDark)
  doc.text('RealSync', MARGIN + 33, 14)

  // Subtitle
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  txt(doc, C.textSubtitle)
  doc.text('AI-Powered Meeting Authenticity Platform', MARGIN + 33, 21)

  // "SECURITY AUDIT REPORT" badge — right side of banner
  const badgeW = 52
  const badgeX = PAGE_W - MARGIN - badgeW
  const badgeY = 10
  const badgeH = 12
  // Cyan border box
  draw(doc, C.cyan)
  doc.setLineWidth(0.5)
  doc.rect(badgeX, badgeY, badgeW, badgeH)
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(7.5)
  txt(doc, C.cyan)
  doc.text('SECURITY AUDIT REPORT', badgeX + badgeW / 2, badgeY + 7.5, { align: 'center' })

  // ── Cyan accent line below banner ──────────────────────────────
  cyanRule(doc, BANNER_H)

  let y = BANNER_H + 6

  // ── Confidentiality notice ──────────────────────────────────────
  doc.setFont('helvetica', 'italic')
  doc.setFontSize(7.5)
  txt(doc, C.textFooter)
  doc.text(
    'CONFIDENTIAL — This report contains security-sensitive information. Distribution is restricted to authorized personnel.',
    PAGE_W / 2, y + 4,
    { align: 'center' },
  )
  y += 10

  hRule(doc, y, C.border)
  y += 8

  // ── Report title ────────────────────────────────────────────────
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(22)
  txt(doc, C.textPrimary)
  doc.text('Meeting Authenticity Report', MARGIN, y)
  y += 8

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(14)
  txt(doc, C.textBody)
  doc.text(report.title, MARGIN, y)
  y += 10

  hRule(doc, y)
  y += 8

  // ── Metadata row (4 columns) ────────────────────────────────────
  const metaCols = [
    { label: 'Date',         value: report.date },
    { label: 'Duration',     value: report.duration },
    { label: 'Meeting Type', value: ((report.meetingType ?? 'Standard').charAt(0).toUpperCase() + (report.meetingType ?? 'Standard').slice(1)) },
    { label: 'Report ID',    value: report.id.slice(0, 8).toUpperCase() },
  ]
  const colW = CONT_W / metaCols.length
  metaCols.forEach((col, i) => {
    const cx = MARGIN + i * colW
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(8)
    txt(doc, C.textLabel)
    doc.text(col.label.toUpperCase(), cx, y)
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(10)
    txt(doc, C.textPrimary)
    doc.text(col.value, cx, y + 6)
  })
  y += 18

  hRule(doc, y)
  y += 10

  // ── Trust Score section ─────────────────────────────────────────
  const scoreColor = riskColor(report.trustAvg)
  const rLabel     = riskLabel(report.trustAvg)

  // Large trust score number
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(32)
  txt(doc, scoreColor)
  doc.text(`${report.trustAvg}%`, MARGIN + 30, y + 18, { align: 'center' })

  // "TRUST SCORE" label
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  txt(doc, C.textLabel)
  doc.text('TRUST SCORE', MARGIN + 30, y + 24, { align: 'center' })

  // Risk level badge
  const badgeTxtW = doc.getTextWidth(rLabel) + 8
  const rBadgeX   = MARGIN + 30 - badgeTxtW / 2
  fill(doc, scoreColor)
  doc.rect(rBadgeX, y + 26, badgeTxtW, 5.5, 'F')
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(7)
  txt(doc, C.textOnDark)
  doc.text(rLabel, MARGIN + 30, y + 30, { align: 'center' })

  // ── Severity breakdown — 4 boxes to the right ──────────────────
  const sevCards = [
    { label: 'Critical', count: report.alerts.critical, color: C.sevCritical },
    { label: 'High',     count: report.alerts.high,     color: C.sevHigh },
    { label: 'Medium',   count: report.alerts.medium,   color: C.sevMedium },
    { label: 'Low',      count: report.alerts.low,      color: C.sevLow },
  ]

  const cardsStartX = MARGIN + 65
  const cardW       = (CONT_W - 65) / 4 - 2
  sevCards.forEach((card, i) => {
    const cx = cardsStartX + i * (cardW + 2.5)
    const col = card.count > 0 ? card.color : C.textLabel

    // Card border
    draw(doc, C.border)
    fill(doc, C.pageBg)
    doc.setLineWidth(0.3)
    doc.rect(cx, y, cardW, 38, 'FD')

    // Count (large)
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(18)
    txt(doc, col)
    doc.text(String(card.count), cx + cardW / 2, y + 18, { align: 'center' })

    // Label
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(7)
    txt(doc, C.textLabel)
    doc.text(card.label.toUpperCase(), cx + cardW / 2, y + 26, { align: 'center' })

    // Thin color top bar
    fill(doc, col)
    doc.rect(cx, y, cardW, 1.5, 'F')
  })

  y += 48

  // ── Executive Summary ────────────────────────────────────────────
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(12)
  txt(doc, C.textPrimary)
  doc.text('Executive Summary', MARGIN, y)
  cyanRule(doc, y + 2.5)
  y += 9

  const summaryText  = buildSummaryText(report)
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(9.5)
  txt(doc, C.textBody)
  const summaryLines = doc.splitTextToSize(summaryText, CONT_W)
  doc.text(summaryLines, MARGIN, y)
  y += summaryLines.length * 5.5 + 6

  drawFooter(doc, 1, totalPages)
}

// --- PAGE 2: Detection Analysis ---

function buildPage2(doc: jsPDF, report: ReportPayload, totalPages: number) {
  doc.addPage()
  fill(doc, C.pageBg)
  doc.rect(0, 0, PAGE_W, PAGE_H, 'F')

  let y = MARGIN

  // Page heading
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(12)
  txt(doc, C.textPrimary)
  doc.text('Detection Analysis', MARGIN, y + 5)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  txt(doc, C.textLabel)
  doc.text('Detailed breakdown of all AI detection layers applied to this session', MARGIN, y + 11)

  cyanRule(doc, y + 14)
  y += 20

  // ── Visual Manipulation Detection ─────────────────────────────
  y = sectionHeading(doc, y, 'Visual Manipulation Detection')

  const visualScore = report.visualScore ?? report.trustAvg
  const vColor      = riskColor(visualScore)

  // Score display row
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(9.5)
  txt(doc, C.textLabel)
  doc.text('Authenticity Score', MARGIN, y + 5)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(22)
  txt(doc, vColor)
  doc.text(`${visualScore}%`, MARGIN + 50, y + 6, { align: 'center' })

  progressBar(doc, MARGIN, y + 9, CONT_W * 0.55, visualScore, vColor)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8.5)
  txt(doc, C.textBody)
  doc.text('Model:', MARGIN + CONT_W * 0.58, y + 4)
  doc.setFont('helvetica', 'bold')
  doc.text(report.modelUsed ?? 'Ensemble (CLIP-ViT + Frequency + Boundary)', MARGIN + CONT_W * 0.58, y + 9)

  doc.setFont('helvetica', 'normal')
  txt(doc, C.textLabel)
  doc.text('Risk Level:', MARGIN + CONT_W * 0.58, y + 14)
  doc.setFont('helvetica', 'bold')
  txt(doc, vColor)
  doc.text(riskLabel(visualScore), MARGIN + CONT_W * 0.58 + doc.getTextWidth('Risk Level:') + 3, y + 14)

  y += 24
  hRule(doc, y)
  y += 8

  // ── Audio Analysis ──────────────────────────────────────────────
  y = sectionHeading(doc, y, 'Audio Analysis')

  const audioScore = report.audioScore ?? Math.min(100, report.trustAvg + 2)
  const aColor     = riskColor(audioScore)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(9.5)
  txt(doc, C.textLabel)
  doc.text('Authenticity Score', MARGIN, y + 5)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(22)
  txt(doc, aColor)
  doc.text(`${audioScore}%`, MARGIN + 50, y + 6, { align: 'center' })

  progressBar(doc, MARGIN, y + 9, CONT_W * 0.55, audioScore, aColor)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(8.5)
  txt(doc, C.textBody)
  doc.text('Model:', MARGIN + CONT_W * 0.58, y + 4)
  doc.setFont('helvetica', 'bold')
  doc.text('WavLM Audio Classifier', MARGIN + CONT_W * 0.58, y + 9)

  doc.setFont('helvetica', 'normal')
  txt(doc, C.textLabel)
  doc.text('Risk Level:', MARGIN + CONT_W * 0.58, y + 14)
  doc.setFont('helvetica', 'bold')
  txt(doc, aColor)
  doc.text(riskLabel(audioScore), MARGIN + CONT_W * 0.58 + doc.getTextWidth('Risk Level:') + 3, y + 14)

  y += 24
  hRule(doc, y)
  y += 8

  // ── Emotion Analysis ────────────────────────────────────────────
  y = sectionHeading(doc, y, 'Emotion Analysis')

  const emotions = report.dominantEmotions?.length
    ? report.dominantEmotions
    : ['Neutral', 'Attentive', 'Engaged']

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(8.5)
  txt(doc, C.textBody)
  doc.text('Dominant Emotions Detected:', MARGIN, y + 5)

  const emotionColors: readonly [number, number, number][] = [
    C.riskGreen, C.sevMedium, C.sevHigh, C.sevCritical, C.cyan,
  ]

  emotions.slice(0, 6).forEach((em, i) => {
    const ex = MARGIN + i * 32
    // Pill background (using border color as neutral bg)
    fill(doc, C.rowAlt)
    draw(doc, C.border)
    doc.setLineWidth(0.2)
    doc.rect(ex, y + 8, 29, 6, 'FD')
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(7)
    txt(doc, emotionColors[i % emotionColors.length])
    doc.text(em.toUpperCase(), ex + 14.5, y + 12.5, { align: 'center' })
  })

  y += 22
  hRule(doc, y)
  y += 8

  // ── Behavioral Analysis ─────────────────────────────────────────
  y = sectionHeading(doc, y, 'Behavioral Analysis')

  const behavMetrics = [
    { label: 'Gaze Consistency',    value: Math.min(100, report.trustAvg + 1) },
    { label: 'Head Pose Stability', value: Math.min(100, Math.max(0, report.trustAvg - 1)) },
    { label: 'Temporal Coherence',  value: report.trustAvg },
  ]

  const metricW = CONT_W / 3 - 4
  behavMetrics.forEach((m, i) => {
    const mx  = MARGIN + i * (metricW + 6)
    const col = riskColor(m.value)

    // Card
    draw(doc, C.border)
    fill(doc, C.rowAlt)
    doc.setLineWidth(0.25)
    doc.rect(mx, y, metricW, 30, 'FD')

    // Thin top color bar
    fill(doc, col)
    doc.rect(mx, y, metricW, 1.5, 'F')

    doc.setFont('helvetica', 'normal')
    doc.setFontSize(8)
    txt(doc, C.textLabel)
    doc.text(m.label, mx + metricW / 2, y + 9, { align: 'center' })

    doc.setFont('helvetica', 'bold')
    doc.setFontSize(18)
    txt(doc, col)
    doc.text(`${m.value}%`, mx + metricW / 2, y + 21, { align: 'center' })

    progressBar(doc, mx + 4, y + 24, metricW - 8, m.value, col)
  })

  drawFooter(doc, 2, totalPages)
}

// --- PAGE 3: Alert Timeline ---

function buildPage3(doc: jsPDF, report: ReportPayload, totalPages: number) {
  doc.addPage()
  fill(doc, C.pageBg)
  doc.rect(0, 0, PAGE_W, PAGE_H, 'F')

  let y = MARGIN

  // Page heading
  doc.setFont('helvetica', 'bold')
  doc.setFontSize(12)
  txt(doc, C.textPrimary)
  doc.text('Alert Timeline', MARGIN, y + 5)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  txt(doc, C.textLabel)
  doc.text('Chronological record of all detection events during this session', MARGIN, y + 11)

  cyanRule(doc, y + 14)
  y += 22

  if (report.timeline.length === 0) {
    // Clean session notice
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(10)
    txt(doc, C.textLabel)
    const cleanMsg = 'No security alerts were detected during this session. All signals remained within acceptable thresholds.'
    const cleanLines = doc.splitTextToSize(cleanMsg, CONT_W - 20)
    doc.text(cleanLines, PAGE_W / 2, y + 20, { align: 'center' })
    drawFooter(doc, 3, totalPages)
    return
  }

  const tableBody = report.timeline.map((alert) => [
    alert.time,
    alert.sev.toUpperCase(),
    alert.cat,
    alert.msg.length > 90 ? alert.msg.slice(0, 90) + '...' : alert.msg,
  ])

  autoTable(doc, {
    startY: y,
    head: [['Time', 'Severity', 'Category', 'Description']],
    body: tableBody,
    theme: 'grid',
    headStyles: {
      fillColor: [26, 26, 46],
      textColor: [255, 255, 255],
      fontSize: 8.5,
      fontStyle: 'bold',
      cellPadding: 3.5,
    },
    styles: {
      fontSize: 8.5,
      cellPadding: 3,
      textColor: [55, 65, 81],
      lineColor: [229, 231, 235],
      lineWidth: 0.25,
    },
    alternateRowStyles: {
      fillColor: [248, 250, 252],
    },
    columnStyles: {
      0: { cellWidth: 22 },
      1: { cellWidth: 24, fontStyle: 'bold' },
      2: { cellWidth: 38 },
      3: { cellWidth: 'auto' },
    },
    margin: { left: MARGIN, right: MARGIN },
    didParseCell: (data: CellHookData) => {
      if (data.section === 'body' && data.column.index === 1) {
        const raw   = data.row.raw
        const sev   = (Array.isArray(raw) ? String(raw[1] ?? '') : '').toLowerCase()
        const color = sevColor(sev)
        data.cell.styles.textColor = [color[0], color[1], color[2]]
      }
    },
  })

  drawFooter(doc, 3, totalPages)
}

// --- PAGE 4: Transcript ---

function buildPage4(doc: jsPDF, report: ReportPayload, totalPages: number) {
  doc.addPage()
  fill(doc, C.pageBg)
  doc.rect(0, 0, PAGE_W, PAGE_H, 'F')

  let y = MARGIN

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(12)
  txt(doc, C.textPrimary)
  doc.text('Session Transcript', MARGIN, y + 5)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(8)
  txt(doc, C.textLabel)
  doc.text('Timestamped transcript of meeting communications', MARGIN, y + 11)

  cyanRule(doc, y + 14)
  y += 22

  if (!report.transcript || report.transcript.length === 0) {
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(9.5)
    txt(doc, C.textLabel)
    doc.text('No transcript data available for this session.', PAGE_W / 2, y + 20, { align: 'center' })
    drawFooter(doc, 4, totalPages)
    return
  }

  const transcriptBody = report.transcript.slice(0, 60).map((line) => [
    line.timestamp,
    line.speaker || '—',
    line.text.length > 100 ? line.text.slice(0, 100) + '...' : line.text,
  ])

  autoTable(doc, {
    startY: y,
    head: [['Time', 'Speaker', 'Text']],
    body: transcriptBody,
    theme: 'grid',
    headStyles: {
      fillColor: [26, 26, 46],
      textColor: [255, 255, 255],
      fontSize: 8.5,
      fontStyle: 'bold',
      cellPadding: 3.5,
    },
    styles: {
      fontSize: 8.5,
      cellPadding: 3,
      textColor: [55, 65, 81],
      lineColor: [229, 231, 235],
      lineWidth: 0.25,
    },
    alternateRowStyles: {
      fillColor: [248, 250, 252],
    },
    columnStyles: {
      0: { cellWidth: 22 },
      1: { cellWidth: 30 },
      2: { cellWidth: 'auto' },
    },
    margin: { left: MARGIN, right: MARGIN },
    didParseCell: (data: CellHookData) => {
      if (data.section === 'body' && data.column.index === 1) {
        const raw     = data.row.raw
        const speaker = Array.isArray(raw) ? String(raw[1] ?? '') : ''
        if (speaker && speaker !== '—') {
          data.cell.styles.textColor = [26, 26, 46]
          data.cell.styles.fontStyle = 'bold'
        }
      }
    },
  })

  if (report.transcript.length > 60) {
    const lastY = (doc as jsPDF & { lastAutoTable?: { finalY: number } }).lastAutoTable?.finalY ?? y + 10
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(7)
    txt(doc, C.textLabel)
    doc.text(`Showing 60 of ${report.transcript.length} transcript entries.`, MARGIN, lastY + 5)
  }

  drawFooter(doc, 4, totalPages)
}

// --- Filename helper ---

function buildFilename(report: ReportPayload): string {
  const sessionIdFirst8 = report.id.slice(0, 8)
  const now = new Date()
  const yyyy = now.getFullYear()
  const mm   = String(now.getMonth() + 1).padStart(2, '0')
  const dd   = String(now.getDate()).padStart(2, '0')
  return `RealSync-Session-Report_${sessionIdFirst8}_${yyyy}-${mm}-${dd}.pdf`
}

// --- Main entry point ---

export async function generateReport(report: ReportPayload): Promise<void> {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  })

  const hasTranscript = Array.isArray(report.transcript) && report.transcript.length > 0
  const totalPages    = hasTranscript ? 4 : 3

  buildPage1(doc, report, totalPages)
  buildPage2(doc, report, totalPages)
  buildPage3(doc, report, totalPages)

  if (hasTranscript) {
    buildPage4(doc, report, totalPages)
  }

  doc.save(buildFilename(report))
}
